window.__SCHOLARSHIP_DETAIL_CB && window.__SCHOLARSHIP_DETAIL_CB({"id":"16580","status":"ok","fetched_at":"2026-06-10T23:27:23Z","official_link":null,"org_about":"Al Qasimia University was established under a royal decree issued by HH Sheikh Dr. Sultan bin Muhammad Al-Qasimi, Member of the Supreme Council, Ruler of Sharjah, No. (2) for 2013, on the establishment of an Islamic, Arab University in the Emirate of Sharjah under the name of \u201cAl Qasimia University\". Occupying a prominent location in the University dormitory in the city of Sharjah, the University has an environmentally friendly campus built according to the latest systems and the highest standards that gather between the beauty of the Islamic architecture and the splendor of designs.","en":{"lang":"en","title":"Fully Funded Bachelor Scholarships in the UAE at Alqasimia University","sections":[{"header":"Opportunity description","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cp\u003eThe Alqasimia University is now accepting applications for the Undergraduate Scholarship program. The scholarship program is limited to students admitted to the university from outside the UAE only.\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"Benefits","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cul\u003e\u003cli\u003eThe scholarship student receives a monthly reward determined by the University (according to regulations and decisions).\u003c/li\u003e\u003cli\u003eThe monthly reward is paid during the summer semester only for enrolled students.\u003c/li\u003e\u003cli\u003eThe scholarship student is entitled for one ticket (round trip) after completing half of the total hours of his specialization provided\u0026nbsp; that his semester average and cumulative should not be\u0026nbsp; less than 2.00 points (throughout the study period).\u003c/li\u003e\u003cli\u003eThe university is responsible for all the procedures of residence and the issuance of ID cards of students.\u003c/li\u003e\u003cli\u003eThe university provides health insurance for all students.\u003c/li\u003e\u003cli\u003eThe university provides adequate accommodation.\u003c/li\u003e\u003cli\u003eThe university only provides on-campus transportation.\u003c/li\u003e\u003cli\u003eThe student is granted a return ticket to his country after graduation.\u003c/li\u003e\u003c/ul\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"Eligibility criteria","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cul\u003e\u003cli\u003eRegistering in courses every semester is a must with no withdrawal or discontinuation.\u003c/li\u003e\u003cli\u003eStudent\u0026#39;s GPA \u0026amp; TGPA in each term must be at least 2.00 (70%) to keep the scholarship.\u003c/li\u003e\u003cli\u003eIf a scholarship student\u0026#39;s GPA or TGPA for any regular term is lower than 2.00 (70%), scholarship terms and conditions apply.\u003c/li\u003e\u003cli\u003eScholarship students must be completely dedicated for study and are not allowed to work during their study period at the University. In case any student violates this condition, their scholarship will be terminated.\u003c/li\u003e\u003cli\u003eScholarship students who join the Intensive Arabic Language Program must complete this program successfully within a maximum period of one academic year, and then they will join one of the available majors according to the admission terms and the availability of seats in each major. If they fail, the University regulations and rules apply.\u003c/li\u003e\u003cli\u003eStudents must be committed to follow the University rules along with all ethical \u0026amp; behavioral regulations on campus.\u003c/li\u003e\u003cli\u003eStudents are not allowed to withdraw from the University or leave the country without prior permission from the University.\u003c/li\u003e\u003cli\u003eThe study is obligatory in the summer semester (due to the nature of study and the students at the university).\u003c/li\u003e\u003cli\u003eIf the student does not attend on time, the arrival visa will be cancelled.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003eSee also the\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003ejob opportunities in the Gulf\u003c/strong\u003e\u003cstrong\u003e\u0026nbsp;on For9a\u003c/strong\u003e\u003c/p\u003e\u003ch3\u003eAbout Alqasimia University :-\u003c/h3\u003e\u003cp\u003eAl Qasimia University was established under a royal decree issued by HH Sheikh Dr. Sultan bin Muhammad Al-Qasimi, Member of the Supreme Council, Ruler of Sharjah, No. (2) for 2026, on the establishment of an Islamic, Arab University in the Emirate of Sharjah under the name of \u0026ldquo;Al Qasimia University\u0026quot;. Occupying a prominent location in the University dormitory in the city of Sharjah, the University has an environmentally friendly campus built according to the latest systems and the highest standards that gather between the beauty of the Islamic architecture and the splendor of designs.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSee more available\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003eworkshops or trainings\u003c/strong\u003e\u003cstrong\u003e\u0026nbsp;on For9a\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSee more available\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003efellowships\u003c/strong\u003e\u003cstrong\u003e\u0026nbsp;on For9a\u003c/strong\u003e\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"}]},"ar":{"lang":"ar","title":"\u0645\u0646\u062d\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0645\u062c\u0627\u0646\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a | \u062a\u0642\u062f\u0645 \u0627\u0644\u0622\u0646!","sections":[{"header":"\u0648\u0635\u0641 \u0627\u0644\u0641\u0631\u0635\u0629","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cp\u003e\u062a\u0639\u0644\u0646 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0639\u0646\u062f \u0628\u062f\u0621 \u0642\u0628\u0648\u0644 \u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0627\u0644\u062a\u062d\u0627\u0642 \u0628\u0628\u0631\u0646\u0627\u0645\u062c \u0645\u0646\u062d \u0627\u0644\u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633. \u064a\u0642\u062a\u0635\u0631 \u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u0645\u0646\u062d \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0639\u0644\u0649 \u0627\u0644\u0637\u0644\u0628\u0629 \u0627\u0644\u0645\u0642\u0628\u0648\u0644\u064a\u0646 \u0641\u064a \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0645\u0646 \u062e\u0627\u0631\u062c \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629 \u0641\u0642\u0637.\u003c/p\u003e\u003cp\u003e\u003c/p\u003e\u003cp\u003e\u062a\u0639\u062a\u0628\u0631 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0641\u0631\u0635\u0629 \u0627\u0633\u062a\u062b\u0646\u0627\u0626\u064a\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646 \u0627\u0644\u0631\u0627\u063a\u0628\u064a\u0646 \u0641\u064a \u062f\u0631\u0627\u0633\u0629 \u0628\u0631\u0627\u0645\u062c \u0627\u0644\u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633 \u0641\u064a \u0628\u064a\u0626\u0629 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0631\u0627\u0626\u062f\u0629\u060c \u062d\u064a\u062b \u062a\u0648\u0641\u0631 \u0644\u0647\u0645 \u062c\u0645\u064a\u0639 \u0627\u0644\u0641\u0631\u0635 \u0627\u0644\u0644\u0627\u0632\u0645\u0629 \u0644\u062a\u062d\u0642\u064a\u0642 \u0627\u0644\u062a\u0641\u0648\u0642 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a. \u0647\u0630\u0647 \u0627\u0644\u0645\u0646\u062d\u0629\u060c \u0627\u0644\u062a\u064a \u062a\u064f\u0642\u062f\u0645 \u0644\u0644\u0637\u0644\u0627\u0628 \u0645\u0646 \u062e\u0627\u0631\u062c \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629\u060c \u062a\u0645\u062b\u0644 \u0628\u0648\u0627\u0628\u0629 \u0625\u0644\u0649 \u062a\u0639\u0644\u064a\u0645 \u0639\u0627\u0644\u064a \u0627\u0644\u062c\u0648\u062f\u0629 \u0641\u064a \u0648\u0627\u062d\u062f\u0629 \u0645\u0646 \u0623\u0628\u0631\u0632 \u0627\u0644\u062c\u0627\u0645\u0639\u0627\u062a \u0641\u064a \u0627\u0644\u0645\u0646\u0637\u0642\u0629. \u062a\u0642\u0639 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0641\u064a \u0627\u0644\u0634\u0627\u0631\u0642\u0629\u060c \u0648\u0647\u064a \u0645\u062f\u064a\u0646\u0629 \u062a\u062a\u0645\u062a\u0639 \u0628\u0645\u0648\u0642\u0639 \u0627\u0633\u062a\u0631\u0627\u062a\u064a\u062c\u064a \u0648\u062c\u0648 \u0623\u0643\u0627\u062f\u064a\u0645\u064a \u0645\u0645\u064a\u0632\u060c \u0645\u0645\u0627 \u064a\u062c\u0639\u0644\u0647\u0627 \u0648\u062c\u0647\u0629 \u0645\u062b\u0627\u0644\u064a\u0629 \u0644\u0644\u0645\u0628\u062f\u0639\u064a\u0646 \u0648\u0627\u0644\u0637\u0645\u0648\u062d\u064a\u0646 \u0645\u0646 \u062c\u0645\u064a\u0639 \u0623\u0646\u062d\u0627\u0621 \u0627\u0644\u0639\u0627\u0644\u0645. \u062a\u0647\u062f\u0641 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0625\u0644\u0649 \u062a\u0645\u0643\u064a\u0646 \u0627\u0644\u0637\u0644\u0627\u0628 \u0639\u0628\u0631 \u062a\u0648\u0641\u064a\u0631 \u0645\u0646\u062d \u062f\u0631\u0627\u0633\u064a\u0629 \u062a\u0645\u0648\u0644 \u0643\u0627\u0641\u0629 \u0627\u062d\u062a\u064a\u0627\u062c\u0627\u062a\u0647\u0645\u060c \u0628\u062f\u0621\u064b\u0627 \u0645\u0646 \u0627\u0644\u0631\u0633\u0648\u0645 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0648\u0635\u0648\u0644\u0627\u064b \u0625\u0644\u0649 \u062a\u0630\u0627\u0643\u0631 \u0627\u0644\u0633\u0641\u0631 \u0648\u0627\u0644\u0625\u0642\u0627\u0645\u0629.\u003c/p\u003e\u003cp\u003e\u0647\u0630\u0647 \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u0641\u062a\u062d \u0623\u0628\u0648\u0627\u0628\u0627\u064b \u062c\u062f\u064a\u062f\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0645\u062a\u0641\u0648\u0642\u064a\u0646 \u0627\u0644\u0630\u064a\u0646 \u064a\u0633\u0639\u0648\u0646 \u0644\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u062a\u0639\u0644\u064a\u0645 \u0623\u0643\u0627\u062f\u064a\u0645\u064a \u0645\u062a\u0645\u064a\u0632 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629\u060c \u0636\u0645\u0646 \u0628\u064a\u0626\u0629 \u062a\u0634\u062c\u0639 \u0639\u0644\u0649 \u0627\u0644\u062a\u0645\u064a\u0632 \u0627\u0644\u0641\u0643\u0631\u064a \u0648\u0627\u0644\u0628\u062d\u062b \u0627\u0644\u0639\u0644\u0645\u064a.\u003c/p\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0627\u0644\u0645\u0632\u064a\u062f: \u0645\u0646\u062d \u062f\u0631\u0627\u0633\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"\u0627\u0644\u0645\u0646\u0627\u0641\u0639 \u0648\u0627\u0644\u0641\u0648\u0627\u0626\u062f","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003ch3\u003e\u003cstrong\u003e\u062a\u0645\u0648\u064a\u0644 \u0648\u0645\u0632\u0627\u064a\u0627 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a:\u003c/strong\u003e\u003c/h3\u003e\u003cp\u003e\u003cstrong\u003e\u003c/strong\u003e\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0634\u0647\u0631\u064a\u0629\u003c/strong\u003e: \u064a\u062a\u0642\u0627\u0636\u0649 \u0637\u0627\u0644\u0628 \u0627\u0644\u0645\u0646\u062d\u0629 \u0645\u0643\u0627\u0641\u0623\u0629 \u0634\u0647\u0631\u064a\u0629 \u062a\u062d\u062f\u062f\u0647\u0627 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0648\u0641\u0642\u0627\u064b \u0644\u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0648\u0627\u0644\u0644\u0648\u0627\u0626\u062d \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647\u0627.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0635\u064a\u0641\u064a\u0629\u003c/strong\u003e: \u064a\u062a\u0645 \u0635\u0631\u0641 \u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0634\u0647\u0631\u064a\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0645\u0633\u062c\u0644\u064a\u0646 \u0641\u0642\u0637 \u0641\u064a \u0641\u0635\u0644 \u0627\u0644\u0635\u064a\u0641 (\u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u0627\u062e\u062a\u064a\u0627\u0631\u064a\u0629 \u062e\u0644\u0627\u0644 \u0627\u0644\u0635\u064a\u0641).\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0630\u0627\u0643\u0631 \u0627\u0644\u0633\u0641\u0631\u003c/strong\u003e: \u062a\u062a\u062d\u0645\u0644 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0646\u0641\u0642\u0627\u062a \u062a\u0630\u0643\u0631\u0629 \u0627\u0644\u0633\u0641\u0631 \u0630\u0647\u0627\u0628\u0627\u064b \u0648\u0625\u064a\u0627\u0628\u0627\u064b \u0645\u0646 \u0628\u0644\u062f \u0627\u0644\u0637\u0627\u0644\u0628 \u0639\u0646\u062f \u0625\u0646\u062c\u0627\u0632\u0647 50% \u0645\u0646 \u062e\u0637\u062a\u0647 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629\u060c \u0634\u0631\u064a\u0637\u0629 \u0623\u0646 \u064a\u062a\u0648\u0627\u0641\u0642 \u0630\u0644\u0643 \u0645\u0639 \u0627\u0644\u062a\u0648\u0642\u064a\u062a\u0627\u062a \u0627\u0644\u0645\u0633\u0645\u0648\u062d \u0628\u0647\u0627 \u0641\u064a \u0627\u0644\u062a\u0642\u0648\u064a\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062a\u0623\u0634\u064a\u0631\u0627\u062a \u0648\u0627\u0644\u0625\u0642\u0627\u0645\u0627\u062a\u003c/strong\u003e: \u062a\u062a\u0643\u0641\u0644 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0628\u0643\u0627\u0641\u0629 \u0646\u0641\u0642\u0627\u062a \u0648\u0625\u062c\u0631\u0627\u0621\u0627\u062a \u0627\u0644\u062a\u0623\u0634\u064a\u0631\u0627\u062a \u0648\u0627\u0644\u0625\u0642\u0627\u0645\u0627\u062a \u0648\u0627\u0633\u062a\u062e\u0631\u0627\u062c \u0628\u0637\u0627\u0642\u0627\u062a \u0627\u0644\u0647\u0648\u064a\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0642\u0627\u062f\u0645\u064a\u0646 \u0645\u0646 \u062e\u0627\u0631\u062c \u0627\u0644\u062f\u0648\u0644\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062a\u0623\u0645\u064a\u0646 \u0627\u0644\u0635\u062d\u064a\u003c/strong\u003e: \u062a\u0648\u0641\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u062a\u0623\u0645\u064a\u0646\u0627\u064b \u0635\u062d\u064a\u0627\u064b \u0648\u0641\u0642\u0627\u064b \u0644\u0644\u0633\u064a\u0627\u0633\u0627\u062a \u0627\u0644\u0645\u0639\u062a\u0645\u062f\u0629 \u0644\u062f\u064a\u0647\u0627.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0633\u0643\u0646\u003c/strong\u003e: \u062a\u0648\u0641\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0633\u0643\u0646\u064b\u0627 \u0644\u0644\u0637\u0644\u0627\u0628 \u062f\u0627\u062e\u0644 \u0623\u0648 \u062e\u0627\u0631\u062c \u0627\u0644\u062d\u0631\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a \u0641\u064a \u0645\u062f\u064a\u0646\u0629 \u0627\u0644\u0634\u0627\u0631\u0642\u0629\u060c \u0625\u0630\u0627 \u0643\u0627\u0646 \u0627\u0644\u0637\u0627\u0644\u0628 \u0642\u0627\u062f\u0645\u064b\u0627 \u0645\u0646 \u0627\u0644\u062e\u0627\u0631\u062c \u0648\u063a\u064a\u0631 \u0645\u062a\u0632\u0648\u062c \u0623\u0648 \u0644\u0627 \u064a\u0639\u0648\u0644. \u0648\u0644\u0627 \u062a\u062a\u062d\u0645\u0644 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0645\u0633\u0624\u0648\u0644\u064a\u0629 \u0627\u0644\u0633\u0643\u0646 \u0625\u0630\u0627 \u062a\u0632\u0648\u062c \u0627\u0644\u0637\u0627\u0644\u0628 \u062e\u0644\u0627\u0644 \u0641\u062a\u0631\u0629 \u062f\u0631\u0627\u0633\u062a\u0647.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0648\u0633\u0627\u0626\u0644 \u0627\u0644\u0646\u0642\u0644\u003c/strong\u003e: \u062a\u0648\u0641\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0648\u0633\u0627\u0626\u0644 \u0627\u0644\u0646\u0642\u0644 \u062f\u0627\u062e\u0644 \u0627\u0644\u062d\u0631\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a \u0641\u0642\u0637.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0630\u0643\u0631\u0629 \u0633\u0641\u0631 \u0628\u0639\u062f \u0627\u0644\u062a\u062e\u0631\u062c\u003c/strong\u003e: \u062a\u0645\u0646\u062d \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u062a\u0630\u0643\u0631\u0629 \u0633\u0641\u0631 \u0630\u0647\u0627\u0628\u064b\u0627 \u0641\u0642\u0637 \u0645\u0646 \u062f\u0648\u0644\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u0625\u0644\u0649 \u0627\u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u062a\u064a \u064a\u062d\u0645\u0644 \u0627\u0644\u0637\u0627\u0644\u0628 \u062c\u0646\u0633\u064a\u062a\u0647\u0627 \u0628\u0639\u062f \u062a\u062e\u0631\u062c\u0647.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0645\u0644\u0643 \u0633\u0639\u0648\u062f \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003ch3\u003e\u003cstrong\u003e\u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629:\u003c/strong\u003e\u003c/h3\u003e\u003cdiv bis_skin_checked=\"1\" dir=\"auto\"\u003e\u003cp\u003e\u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u062a\u062a\u062c\u062f\u062f \u0633\u0646\u0648\u064a\u064b\u0627\u060c \u0648\u0639\u0627\u062f\u0629\u064b \u0645\u0627 \u062a\u0641\u062a\u062d \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0628\u0627\u0628 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0642\u0628\u0644 \u0628\u062f\u0627\u064a\u0629 \u0643\u0644 \u0641\u0635\u0644 \u062f\u0631\u0627\u0633\u064a\u060c \u0633\u0648\u0627\u0621 \u0644\u0644\u0641\u0635\u0644 \u0627\u0644\u0623\u0648\u0644 \u0627\u0644\u0630\u064a \u064a\u0628\u062f\u0623 \u0641\u064a \u0633\u0628\u062a\u0645\u0628\u0631 \u0623\u0648 \u0627\u0644\u0641\u0635\u0644 \u0627\u0644\u062b\u0627\u0646\u064a \u0627\u0644\u0630\u064a \u064a\u0628\u062f\u0623 \u0641\u064a \u064a\u0646\u0627\u064a\u0631. \u0644\u0630\u0644\u0643\u060c \u064a\u064f\u0646\u0635\u062d \u0644\u0644\u0645\u062a\u0642\u062f\u0645\u064a\u0646 \u0627\u0644\u0631\u0627\u063a\u0628\u064a\u0646 \u0628\u0627\u0644\u0627\u0633\u062a\u0641\u0627\u062f\u0629 \u0645\u0646 \u0647\u0630\u0647 \u0627\u0644\u0645\u0646\u062d\u0629 \u0628\u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0644\u062c\u0627\u0645\u0639\u0629 \u0628\u0634\u0643\u0644 \u062f\u0648\u0631\u064a\u060c \u062d\u064a\u062b \u064a\u062a\u0645 \u0627\u0644\u0625\u0639\u0644\u0627\u0646 \u0639\u0646 \u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u062f\u0642\u064a\u0642\u0629 \u0648\u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u0646\u0647\u0627\u0626\u064a\u0629. \u0643\u0645\u0627 \u064a\u0645\u0643\u0646 \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0645\u0643\u062a\u0628 \u0627\u0644\u0642\u0628\u0648\u0644 \u0648\u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0644\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0623\u062d\u062f\u062b \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u062d\u0648\u0644 \u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0648\u0627\u0644\u0625\u062c\u0631\u0627\u0621\u0627\u062a \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629.\u003c/p\u003e\u003cp\u003e\u062a\u0635\u0641\u062d \u0627\u0644\u0645\u0632\u064a\u062f: \u0645\u0646\u062d\u0629 \u0627\u0644\u062d\u0643\u0648\u0645\u0629 \u0627\u0644\u062a\u0631\u0643\u064a\u0629 \u0645\u0645\u0648\u0644\u0629 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"},{"header":"\u0645\u0639\u0627\u064a\u064a\u0631 \u0627\u0644\u062a\u0642\u062f\u064a\u0645","body":"\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003cdiv bis_skin_checked=\"1\"\u003e\u003ch3\u003e\u003cstrong\u003e\u0634\u0631\u0648\u0637 \u0648\u0645\u0639\u0627\u064a\u064a\u0631 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629:\u003c/strong\u003e\u003c/h3\u003e\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0627\u0644\u062a\u0633\u062c\u064a\u0644\u003c/strong\u003e: \u064a\u062a\u0648\u062c\u0628 \u0639\u0644\u0649 \u0627\u0644\u0637\u0627\u0644\u0628 \u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0641\u064a \u0643\u0644 \u0641\u0635\u0644 \u062f\u0631\u0627\u0633\u064a \u062f\u0648\u0646 \u0627\u0646\u0642\u0637\u0627\u0639 \u0639\u0646 \u0627\u0644\u062f\u0631\u0627\u0633\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0645\u0639\u062f\u0644 \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u064a\u062c\u0628 \u0623\u0644\u0627 \u064a\u0642\u0644 \u0627\u0644\u0645\u0639\u062f\u0644 \u0627\u0644\u0641\u0635\u0644\u064a \u0648\u0627\u0644\u062a\u0631\u0627\u0643\u0645\u064a \u0639\u0646 \u003cstrong\u003e2.00 \u0646\u0642\u0637\u0629\u003c/strong\u003e \u0641\u064a \u0627\u0644\u0641\u0635\u0648\u0644 \u0627\u0644\u0627\u0639\u062a\u064a\u0627\u062f\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0641\u064a \u062d\u0627\u0644 \u062a\u062f\u0646\u064a \u0627\u0644\u0645\u0639\u062f\u0644 \u0639\u0646 \u0647\u0630\u0627 \u0627\u0644\u062d\u062f\u060c \u064a\u062a\u0645 \u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0636\u0648\u0627\u0628\u0637 \u0648\u0627\u0644\u062a\u0639\u0644\u064a\u0645\u0627\u062a \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0627\u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062a\u0641\u0631\u063a \u0644\u0644\u062f\u0631\u0627\u0633\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u064a\u0634\u062a\u0631\u0637 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0627\u0644\u0637\u0627\u0644\u0628 \u0645\u062a\u0641\u0631\u063a\u064b\u0627 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u0644\u062f\u0631\u0627\u0633\u0629.\u003c/li\u003e\u003cli\u003e\u064a\u062d\u0638\u0631 \u0639\u0644\u0649 \u0627\u0644\u0637\u0627\u0644\u0628 \u0627\u0644\u0639\u0645\u0644 \u0623\u062b\u0646\u0627\u0621 \u0641\u062a\u0631\u0629 \u062f\u0631\u0627\u0633\u062a\u0647\u060c \u0648\u0641\u064a \u062d\u0627\u0644 \u0645\u062e\u0627\u0644\u0641\u0629 \u0647\u0630\u0627 \u0627\u0644\u0634\u0631\u0637 \u062a\u064f\u0644\u063a\u0649 \u0627\u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0628\u0631\u0646\u0627\u0645\u062c\u0026nbsp;\u003c/strong\u003e\u003cbr\u003e\u003cstrong\u003e\u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629\u003c/strong\u003e\u003cstrong\u003e\u0026nbsp;\u0627\u0644\u0645\u0643\u062b\u0641\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u064a\u062c\u0628 \u0639\u0644\u0649 \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0645\u0644\u062a\u062d\u0642\u064a\u0646 \u0628\u0647\u0630\u0627 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0625\u062a\u0645\u0627\u0645\u0647 \u0628\u0646\u062c\u0627\u062d \u062e\u0644\u0627\u0644 \u0639\u0627\u0645 \u062f\u0631\u0627\u0633\u064a \u0648\u0627\u062d\u062f \u0643\u062d\u062f \u0623\u0642\u0635\u0649.\u003c/li\u003e\u003cli\u003e\u0639\u0646\u062f \u0627\u062c\u062a\u064a\u0627\u0632 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c\u060c \u064a\u062a\u0645 \u062a\u0646\u0633\u064a\u0628 \u0627\u0644\u0637\u0627\u0644\u0628 \u0625\u0644\u0649 \u0623\u062d\u062f \u062a\u062e\u0635\u0635\u0627\u062a \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0628\u0646\u0627\u0621\u064b \u0639\u0644\u0649 \u0634\u0631\u0648\u0637 \u0627\u0644\u0642\u0628\u0648\u0644 \u0648\u0627\u0644\u0645\u0642\u0627\u0639\u062f \u0627\u0644\u0645\u062a\u0627\u062d\u0629.\u003c/li\u003e\u003cli\u003e\u0641\u064a \u062d\u0627\u0644 \u0639\u062f\u0645 \u0627\u062c\u062a\u064a\u0627\u0632 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c\u060c \u062a\u064f\u0637\u0628\u0642 \u0644\u0648\u0627\u0626\u062d \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0630\u0627\u062a \u0627\u0644\u0635\u0644\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0627\u0644\u0644\u0648\u0627\u0626\u062d \u0648\u0627\u0644\u0642\u0648\u0627\u0646\u064a\u0646\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0639\u0644\u0649 \u0627\u0644\u0637\u0627\u0644\u0628 \u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0644\u0648\u0627\u0626\u062d \u0627\u0644\u062c\u0627\u0645\u0639\u0629\u060c \u0648\u0627\u0644\u0636\u0648\u0627\u0628\u0637 \u0627\u0644\u0633\u0644\u0648\u0643\u064a\u0629 \u0648\u0627\u0644\u0623\u062e\u0644\u0627\u0642\u064a\u0629\u060c \u0648\u0623\u0639\u0631\u0627\u0641 \u0627\u0644\u0645\u062c\u062a\u0645\u0639.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0625\u0630\u0646 \u0627\u0644\u0645\u063a\u0627\u062f\u0631\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0644\u0627 \u064a\u064f\u0633\u0645\u062d \u0644\u0644\u0637\u0627\u0644\u0628 \u0628\u062a\u0631\u0643 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0623\u0648 \u0645\u063a\u0627\u062f\u0631\u0629 \u0627\u0644\u062f\u0648\u0644\u0629 \u0625\u0644\u0627 \u0628\u0625\u0630\u0646 \u0645\u0633\u0628\u0642 \u0645\u0646 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0648\u0628\u062a\u0642\u062f\u064a\u0645 \u0623\u0639\u0630\u0627\u0631 \u0645\u0642\u0628\u0648\u0644\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u0641\u064a \u0641\u0635\u0644 \u0627\u0644\u0635\u064a\u0641\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u062e\u0644\u0627\u0644 \u0641\u0635\u0644 \u0627\u0644\u0635\u064a\u0641 \u0625\u0644\u0632\u0627\u0645\u064a\u0629 \u0648\u0641\u0642\u064b\u0627 \u0644\u0637\u0628\u064a\u0639\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u0648\u0645\u062a\u0637\u0644\u0628\u0627\u062a \u0627\u0644\u062c\u0627\u0645\u0639\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062d\u0636\u0648\u0631 \u0641\u064a \u0627\u0644\u0648\u0642\u062a \u0627\u0644\u0645\u062d\u062f\u062f\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0625\u0630\u0627 \u062a\u0623\u062e\u0631 \u0627\u0644\u0637\u0627\u0644\u0628 \u0639\u0646 \u0627\u0644\u062d\u0636\u0648\u0631 \u0641\u064a \u0627\u0644\u0645\u0648\u0639\u062f \u0627\u0644\u0645\u062d\u062f\u062f\u060c \u062a\u064f\u0644\u063a\u0649 \u062a\u0623\u0634\u064a\u0631\u062a\u0647.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e\u0627\u0637\u0651\u0644\u0639 \u0623\u064a\u0636\u064b\u0627 \u0639\u0644\u0649\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003e\u0648\u0638\u0627\u0626\u0641 \u0641\u064a \u0627\u0644\u062e\u0644\u064a\u062c\u003c/strong\u003e\u003cstrong\u003e\u0026nbsp;\u0627\u0644\u0645\u062a\u0627\u062d\u0629 \u0639\u0644\u0649 \u0641\u0631\u0635\u0629\u003c/strong\u003e\u003c/p\u003e\u003cdiv bis_skin_checked=\"1\" dir=\"auto\"\u003e\u003ch3\u003e\u003cstrong\u003e\u0627\u0644\u0648\u062b\u0627\u0626\u0642 \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0644\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0640 \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629:\u003c/strong\u003e\u003c/h3\u003e\u003col\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u062b\u0627\u0646\u0648\u064a\u0629 \u0627\u0644\u0623\u0635\u0644\u064a\u0629\u003c/strong\u003e: \u0646\u0633\u062e\u0629 \u0623\u0635\u0644\u064a\u0629 \u0645\u0646 \u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u062b\u0627\u0646\u0648\u064a\u0629 \u0627\u0644\u0639\u0627\u0645\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0643\u0634\u0648\u0641 \u062f\u0631\u062c\u0627\u062a \u0627\u0644\u0645\u0631\u062d\u0644\u0629 \u0627\u0644\u062b\u0627\u0646\u0648\u064a\u0629\u003c/strong\u003e: \u0627\u0644\u0646\u0633\u062e \u0627\u0644\u0623\u0635\u0644\u064a\u0629 \u0644\u062f\u0631\u062c\u0627\u062a \u0627\u0644\u0635\u0641\u0648\u0641 \u0627\u0644\u0639\u0627\u0634\u0631\u060c \u0627\u0644\u062d\u0627\u062f\u064a \u0639\u0634\u0631\u060c \u0648\u0627\u0644\u062b\u0627\u0646\u064a \u0639\u0634\u0631.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0644\u062a\u0635\u062f\u064a\u0642\u0627\u062a \u0627\u0644\u0631\u0633\u0645\u064a\u0629\u003c/strong\u003e: \u062a\u0635\u062f\u064a\u0642 \u062c\u0645\u064a\u0639 \u0627\u0644\u0634\u0647\u0627\u062f\u0627\u062a \u0645\u0646 \u0627\u0644\u062c\u0647\u0627\u062a \u0627\u0644\u062a\u0627\u0644\u064a\u0629:\u003cul\u003e\u003cli\u003e\u0648\u0632\u0627\u0631\u0629 \u0627\u0644\u062a\u0631\u0628\u064a\u0629 \u0648\u0627\u0644\u062a\u0639\u0644\u064a\u0645.\u003c/li\u003e\u003cli\u003e\u0648\u0632\u0627\u0631\u0629 \u0627\u0644\u062e\u0627\u0631\u062c\u064a\u0629 \u0641\u064a \u0627\u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u0645\u0635\u062f\u0631\u0629 \u0644\u0644\u0634\u0647\u0627\u062f\u0629.\u003c/li\u003e\u003cli\u003e\u0633\u0641\u0627\u0631\u0629 \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0641\u064a \u0627\u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u0645\u0639\u0646\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0641\u064a \u062d\u0627\u0644 \u0639\u062f\u0645 \u0648\u062c\u0648\u062f \u0633\u0641\u0627\u0631\u0629 \u0625\u0645\u0627\u0631\u0627\u062a\u064a\u0629\u060c \u064a\u0645\u0643\u0646 \u0627\u0644\u062a\u0635\u062f\u064a\u0642 \u0645\u0646 \u0633\u0641\u0627\u0631\u0629 \u0625\u062d\u062f\u0649 \u0627\u0644\u062f\u0648\u0644 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0639\u0627\u0645\u0644\u0629 \u0641\u064a \u062a\u0644\u0643 \u0627\u0644\u062f\u0648\u0644\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0631\u062c\u0645\u0629 \u0627\u0644\u0634\u0647\u0627\u062f\u0627\u062a \u0627\u0644\u0623\u062c\u0646\u0628\u064a\u0629\u003c/strong\u003e: \u062a\u0631\u062c\u0645\u0629 \u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0625\u0644\u0649 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0623\u0648 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u060c \u0648\u062a\u0635\u062f\u064a\u0642\u0647\u0627 \u0645\u0646 \u0627\u0644\u062c\u0647\u0627\u062a \u0627\u0644\u0645\u0630\u0643\u0648\u0631\u0629 \u0623\u0639\u0644\u0627\u0647.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0625\u062b\u0628\u0627\u062a \u0627\u0644\u0627\u0639\u062a\u0631\u0627\u0641 \u0628\u0627\u0644\u0634\u0647\u0627\u062f\u0629\u003c/strong\u003e: \u0645\u0633\u062a\u0646\u062f \u064a\u062b\u0628\u062a \u0627\u0639\u062a\u0631\u0627\u0641 \u0648\u0632\u0627\u0631\u0629 \u0627\u0644\u062a\u0631\u0628\u064a\u0629 \u0648\u0627\u0644\u062a\u0639\u0644\u064a\u0645 \u0641\u064a \u0627\u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u0645\u0635\u062f\u0631\u0629 \u0628\u0627\u0644\u0634\u0647\u0627\u062f\u0629\u060c \u0645\u0639 \u062a\u0623\u0643\u064a\u062f \u0623\u0646 \u062e\u0631\u064a\u062c\u064a \u0627\u0644\u0645\u062f\u0631\u0633\u0629 \u0623\u0648 \u0627\u0644\u0645\u0639\u0647\u062f \u064a\u0645\u0643\u0646\u0647\u0645 \u0627\u0644\u0627\u0644\u062a\u062d\u0627\u0642 \u0628\u0627\u0644\u062c\u0627\u0645\u0639\u0627\u062a \u0627\u0644\u062d\u0643\u0648\u0645\u064a\u0629 \u0641\u064a \u062a\u0644\u0643 \u0627\u0644\u062f\u0648\u0644\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u062a\u0631\u062c\u0645\u0629 \u062c\u0648\u0627\u0632 \u0627\u0644\u0633\u0641\u0631\u003c/strong\u003e: \u062a\u0631\u062c\u0645\u0629 \u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0644\u062c\u0648\u0627\u0632 \u0627\u0644\u0633\u0641\u0631 \u0625\u0644\u0649 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629\u060c \u0648\u062a\u0635\u062f\u064a\u0642\u0647 \u0645\u0646 \u0648\u0632\u0627\u0631\u0629 \u0627\u0644\u062e\u0627\u0631\u062c\u064a\u0629 \u0641\u064a \u062f\u0648\u0644\u0629 \u0627\u0644\u0637\u0627\u0644\u0628 \u0648\u0633\u0641\u0627\u0631\u0629 \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0627\u0633\u062a\u0645\u0627\u0631\u0629 \u0637\u0644\u0628 \u0627\u0644\u0627\u0644\u062a\u062d\u0627\u0642\u003c/strong\u003e: \u062a\u0639\u0628\u0626\u0629 \u0627\u0633\u062a\u0645\u0627\u0631\u0629 \u0627\u0644\u0637\u0644\u0628 \u0643\u0627\u0645\u0644\u0629 \u0648\u0628\u0634\u0643\u0644 \u0635\u062d\u064a\u062d.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u003c/strong\u003e (\u0639\u0646\u062f \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0643\u0644\u064a\u0627\u062a \u0645\u062d\u062f\u062f\u0629):\u003cul\u003e\u003cli\u003e\u003cstrong\u003e\u0643\u0644\u064a\u0629 \u0627\u0644\u0627\u0642\u062a\u0635\u0627\u062f \u0648\u0627\u0644\u0625\u062f\u0627\u0631\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062a\u0648\u0641\u0644: (IBT 61)\u060c \u0623\u0648 (CBT 173)\u060c \u0623\u0648 (PBT 500).\u003c/li\u003e\u003cli\u003eIELTS: \u0645\u062c\u0645\u0648\u0639 \u0644\u0627 \u064a\u0642\u0644 \u0639\u0646 (5.0).\u003c/li\u003e\u003cli\u003e\u0627\u062e\u062a\u0628\u0627\u0631 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0642\u064a\u0627\u0633\u064a (EMSAT): \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 (1200)\u060c \u0627\u0644\u0631\u064a\u0627\u0636\u064a\u0627\u062a (600)\u060c \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 (600).\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0643\u0644\u064a\u0629 \u0627\u0644\u0627\u062a\u0635\u0627\u0644\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062a\u0648\u0641\u0644: (IBT 45)\u060c \u0623\u0648 (CBT 133)\u060c \u0623\u0648 (PBT 450).\u003c/li\u003e\u003cli\u003eIELTS: \u0645\u062c\u0645\u0648\u0639 \u0644\u0627 \u064a\u0642\u0644 \u0639\u0646 (4.5).\u003c/li\u003e\u003cli\u003e\u0627\u062e\u062a\u0628\u0627\u0631 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0642\u064a\u0627\u0633\u064a (EMSAT): \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 (950).\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u0645\u0644\u0627\u062d\u0638\u0629: \u062a\u0643\u0627\u0644\u064a\u0641 \u0627\u0645\u062a\u062d\u0627\u0646\u0627\u062a \u0627\u0644\u062a\u0648\u0641\u0644 \u0623\u0648 \u0627\u0644\u0622\u064a\u0644\u062a\u0633 \u064a\u062a\u062d\u0645\u0644\u0647\u0627 \u0627\u0644\u0637\u0627\u0644\u0628.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0635\u0648\u0631\u0629 \u0645\u0646 \u062c\u0648\u0627\u0632 \u0627\u0644\u0633\u0641\u0631\u003c/strong\u003e: \u0646\u0633\u062e\u0629 \u0633\u0627\u0631\u064a\u0629 \u0627\u0644\u0645\u0641\u0639\u0648\u0644 \u0644\u0645\u062f\u0629 \u0644\u0627 \u062a\u0642\u0644 \u0639\u0646 \u0633\u0646\u062a\u064a\u0646.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0635\u0648\u0631 \u0634\u062e\u0635\u064a\u0629\u003c/strong\u003e: 12 \u0635\u0648\u0631\u0629 \u0634\u062e\u0635\u064a\u0629 \u062d\u062f\u064a\u062b\u0629 \u0648\u0645\u0644\u0648\u0646\u0629 \u0628\u062d\u062c\u0645 (3\u0026times;4) \u0628\u062e\u0644\u0641\u064a\u0629 \u0628\u064a\u0636\u0627\u0621.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0634\u0647\u0627\u062f\u0629 \u0625\u062b\u0628\u0627\u062a \u0627\u0644\u062d\u0627\u0644\u0629 \u0627\u0644\u062c\u0646\u0627\u0626\u064a\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u062a\u0641\u064a\u062f \u062d\u0633\u0646 \u0627\u0644\u0633\u064a\u0631\u0629 \u0648\u0627\u0644\u0633\u0644\u0648\u0643.\u003c/li\u003e\u003cli\u003e\u0635\u0627\u062f\u0631\u0629 \u0645\u0646 \u0627\u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u062a\u064a \u064a\u062d\u0645\u0644 \u0627\u0644\u0637\u0627\u0644\u0628 \u062c\u0646\u0633\u064a\u062a\u0647\u0627.\u003c/li\u003e\u003cli\u003e\u0645\u062a\u0631\u062c\u0645\u0629 \u062a\u0631\u062c\u0645\u0629 \u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0625\u0644\u0649 \u0627\u0644\u0644\u063a\u062a\u064a\u0646 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0648\u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0635\u0648\u0631\u0629 \u0645\u0646 \u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u0645\u064a\u0644\u0627\u062f\u003c/strong\u003e: \u0623\u0648 \u0645\u0627 \u064a\u0639\u0627\u062f\u0644\u0647\u0627\u060c \u0645\u062a\u0631\u062c\u0645\u0629 \u0642\u0627\u0646\u0648\u0646\u064a\u0627\u064b \u0625\u0630\u0627 \u0644\u0645 \u062a\u0643\u0646 \u0628\u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0623\u0648 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u003cstrong\u003e\u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u0644\u064a\u0627\u0642\u0629 \u0627\u0644\u0635\u062d\u064a\u0629\u003c/strong\u003e:\u003cul\u003e\u003cli\u003e\u0635\u0627\u062f\u0631\u0629 \u0645\u0646 \u0645\u0633\u062a\u0634\u0641\u0649 \u062d\u0643\u0648\u0645\u064a \u0641\u064a \u062f\u0648\u0644\u0629 \u0627\u0644\u0637\u0627\u0644\u0628.\u003c/li\u003e\u003cli\u003e\u062a\u0641\u064a\u062f \u0628\u062e\u0644\u0648 \u0627\u0644\u0637\u0627\u0644\u0628 \u0645\u0646 \u0627\u0644\u0623\u0645\u0631\u0627\u0636 \u0627\u0644\u0645\u0639\u062f\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0645\u0635\u062f\u0642\u0629 \u0645\u0646 \u0648\u0632\u0627\u0631\u0629 \u0627\u0644\u062e\u0627\u0631\u062c\u064a\u0629 \u0641\u064a \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0635\u062f\u0627\u0631.\u003c/li\u003e\u003cli\u003e\u0635\u0627\u0644\u062d\u0629 \u0644\u0645\u062f\u0629 \u0644\u0627 \u062a\u0632\u064a\u062f \u0639\u0646 \u062b\u0644\u0627\u062b\u0629 \u0623\u0634\u0647\u0631 \u0645\u0646 \u062a\u0627\u0631\u064a\u062e \u0627\u0644\u0625\u0635\u062f\u0627\u0631.\u003c/li\u003e\u003c/ul\u003e\u003c/li\u003e\u003c/ol\u003e\u003cp\u003e\u062a\u0642\u062f\u0645 \u0627\u0644\u0622\u0646: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u0642\u0637\u0631\u003c/p\u003e\u003c/div\u003e\u003ch3\u003e\u003cstrong\u003e\u0639\u0646 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629:\u003c/strong\u003e\u003c/h3\u003e\u003cp\u003e\u003c/p\u003e\u003cp\u003e\u062a\u0623\u0633\u0633\u062a \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 \u0628\u0645\u0648\u062c\u0628 \u0645\u0631\u0633\u0648\u0645 \u0623\u0645\u064a\u0631\u064a \u0623\u0635\u062f\u0631\u0647 \u0627\u0644\u0634\u064a\u062e \u0627\u0644\u062f\u0643\u062a\u0648\u0631 \u0633\u0644\u0637\u0627\u0646 \u0628\u0646 \u0645\u062d\u0645\u062f \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u060c \u0639\u0636\u0648 \u0627\u0644\u0645\u062c\u0644\u0633 \u0627\u0644\u0623\u0639\u0644\u0649\u060c \u062d\u0627\u0643\u0645 \u0627\u0644\u0634\u0627\u0631\u0642\u0629\u060c \u0628\u0634\u0623\u0646 \u0625\u0646\u0634\u0627\u0621 \u062c\u0627\u0645\u0639\u0629 \u0625\u0633\u0644\u0627\u0645\u064a\u0629 \u0639\u0631\u0628\u064a\u0629 \u0641\u064a \u0625\u0645\u0627\u0631\u0629 \u0627\u0644\u0634\u0627\u0631\u0642\u0629 \u062a\u0633\u0645\u0649 \u0026quot;\u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629\u0026quot;. \u062a\u0642\u0639 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0641\u064a \u0645\u0648\u0642\u0639 \u0645\u062a\u0645\u064a\u0632 \u0641\u064a \u0627\u0644\u0645\u062f\u064a\u0646\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u064a\u0629 \u0641\u064a \u0645\u062f\u064a\u0646\u0629 \u0627\u0644\u0634\u0627\u0631\u0642\u0629\u060c \u0648\u062a\u062d\u062a\u0648\u064a \u0639\u0644\u0649 \u062d\u0631\u0645 \u062c\u0627\u0645\u0639\u064a \u0635\u062f\u064a\u0642 \u0644\u0644\u0628\u064a\u0626\u0629\u060c \u0628\u064f\u0646\u0650\u064a\u064e \u0628\u0623\u062d\u062f\u062b \u0627\u0644\u0646\u0638\u0645 \u0648\u0641\u0642 \u0623\u0639\u0644\u0649 \u0627\u0644\u0645\u0639\u0627\u064a\u064a\u0631\u060c \u0648\u062c\u0645\u0639 \u0628\u064a\u0646 \u062c\u0645\u0627\u0644 \u0627\u0644\u0639\u0645\u0627\u0631\u0629 \u0627\u0644\u0625\u0633\u0644\u0627\u0645\u064a\u0629 \u0648\u0631\u0648\u0639\u0629 \u0627\u0644\u062a\u0635\u0627\u0645\u064a\u0645. \u0643\u0630\u0644\u0643 \u062a\u062d\u062a\u0648\u064a \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0639\u0644\u0649 \u0645\u062c\u0645\u0648\u0639\u0629 \u0645\u062a\u0643\u0627\u0645\u0644\u0629 \u0645\u0646 \u0627\u0644\u062e\u062f\u0645\u0627\u062a \u0627\u0644\u062a\u064a \u062a\u0648\u0641\u0631\u0647\u0627 \u0644\u062f\u0639\u0645 \u0627\u0644\u0637\u0644\u0628\u0629\u060c \u062d\u0631\u0635\u0627\u064b \u0645\u0646\u0647\u0627 \u0639\u0644\u0649 \u062e\u0644\u0642 \u0628\u064a\u0626\u0629 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u062c\u0627\u0630\u0628\u0629 \u0648\u0645\u062a\u0645\u064a\u0632\u0629 \u062a\u062e\u062f\u0645 \u0643\u0627\u0641\u0629 \u0627\u0644\u0637\u0644\u0628\u0629 \u0645\u0646 \u062c\u0645\u064a\u0639 \u0623\u0646\u062d\u0627\u0621 \u0627\u0644\u0645\u0639\u0645\u0648\u0631\u0629\u061b \u0644\u062a\u062d\u0642\u0642 \u0631\u0624\u064a\u0629 \u0645\u0624\u0633\u0633\u0647\u0627\u060c \u0635\u0627\u062d\u0628 \u0627\u0644\u0633\u0645\u0648 \u0627\u0644\u0634\u064a\u062e \u0627\u0644\u062f\u0643\u062a\u0648\u0631 \u0633\u0644\u0637\u0627\u0646 \u0628\u0646 \u0645\u062d\u0645\u062f \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u060c \u0639\u0636\u0648 \u0627\u0644\u0645\u062c\u0644\u0633 \u0627\u0644\u0623\u0639\u0644\u0649\u060c \u062d\u0627\u0643\u0645 \u0627\u0644\u0634\u0627\u0631\u0642\u0629\u060c \u0631\u0626\u064a\u0633 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629\u061b \u0648\u0644\u062a\u0643\u0648\u0646 \u0645\u0646\u0627\u0631\u0629 \u0644\u0644\u062a\u0645\u064a\u0632 \u0641\u064a \u0627\u0644\u062a\u0639\u0644\u064a\u0645 \u0627\u0644\u0639\u0627\u0644\u064a \u0648\u0627\u0644\u0628\u062d\u062b \u0627\u0644\u0639\u0644\u0645\u064a\u060c \u0645\u0633\u062a\u0631\u0634\u062f\u0629 \u0641\u064a \u0643\u0644 \u0645\u0627 \u062a\u0642\u0648\u0645 \u0628\u0647 \u0628\u0623\u0633\u0633 \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u0648\u0645\u0628\u0627\u062f\u0626\u0647 \u0648\u062a\u0639\u0627\u0644\u064a\u0645\u0647 \u0627\u0644\u0633\u0645\u062d\u0629 \u0627\u0644\u0645\u0646\u0641\u062a\u062d\u0629 \u0639\u0644\u0649 \u0627\u0644\u0639\u0627\u0644\u0645 \u0623\u062c\u0645\u0639.\u003c/p\u003e\u003cp\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b: \u0645\u0646\u062d\u0629 \u062c\u0627\u0645\u0639\u0629 \u062f\u0627\u064a\u062a\u0648\u0646 \u0644\u0644\u062f\u0631\u0627\u0633\u0629 \u0641\u064a \u0627\u0644\u0648\u0644\u0627\u064a\u0627\u062a \u0627\u0644\u0645\u062a\u062d\u062f\u0629 \u0627\u0644\u0623\u0645\u0631\u064a\u0643\u064a\u0629\u003c/p\u003e\u003cp\u003e\u003cbr\u003e\u003c/p\u003e\u003ch2\u003e\u003cstrong\u003e*\u0623\u0633\u0626\u0644\u0629 \u0634\u0627\u0626\u0639\u0629 \u062d\u0648\u0644 \u0645\u0646\u062d\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629 FAQs:\u003c/strong\u003e\u003c/h2\u003e\u003cp\u003e\u003cstrong\u003e1. \u0645\u0646 \u064a\u0645\u0643\u0646\u0647 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0644\u0645\u0646\u062d\u0629 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u0627\u0644\u0645\u0646\u062d\u0629 \u0645\u062e\u0635\u0635\u0629 \u0644\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u062f\u0648\u0644\u064a\u064a\u0646 \u0645\u0646 \u062e\u0627\u0631\u062c \u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629 \u0627\u0644\u0630\u064a\u0646 \u064a\u0631\u063a\u0628\u0648\u0646 \u0641\u064a \u0645\u062a\u0627\u0628\u0639\u0629 \u062f\u0631\u0627\u0633\u062a\u0647\u0645 \u0627\u0644\u062c\u0627\u0645\u0639\u064a\u0629 \u0641\u064a \u0628\u0631\u0627\u0645\u062c \u0627\u0644\u0628\u0643\u0627\u0644\u0648\u0631\u064a\u0648\u0633.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e2. \u0647\u0644 \u062a\u0634\u0645\u0644 \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u063a\u0637\u064a\u0629 \u0643\u0627\u0645\u0644\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u0646\u0639\u0645\u060c \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u063a\u0637\u064a:\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u0627\u0644\u0631\u0633\u0648\u0645 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0633\u0643\u0646 \u0627\u0644\u062c\u0627\u0645\u0639\u064a.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u062a\u0623\u0645\u064a\u0646 \u0627\u0644\u0635\u062d\u064a.\u003c/li\u003e\u003cli\u003e\u062a\u0630\u0627\u0643\u0631 \u0627\u0644\u0633\u0641\u0631 (\u0639\u0646\u062f \u0625\u0643\u0645\u0627\u0644 50% \u0645\u0646 \u0627\u0644\u062e\u0637\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629).\u003c/li\u003e\u003cli\u003e\u0645\u0635\u0627\u0631\u064a\u0641 \u0627\u0644\u0625\u0642\u0627\u0645\u0629 \u0648\u0627\u0644\u062a\u0623\u0634\u064a\u0631\u0627\u062a.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003e3. \u0645\u0627 \u0647\u064a \u0627\u0644\u0645\u0648\u0627\u0639\u064a\u062f \u0627\u0644\u0645\u062a\u0627\u062d\u0629 \u0644\u0644\u062a\u0642\u062f\u064a\u0645\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u064a\u064f\u0641\u062a\u062d \u0628\u0627\u0628 \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0642\u0628\u0644 \u0628\u062f\u0627\u064a\u0629 \u0643\u0644 \u0641\u0635\u0644 \u062f\u0631\u0627\u0633\u064a:\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u0627\u0644\u0641\u0635\u0644 \u0627\u0644\u0623\u0648\u0644: \u0639\u0627\u062f\u0629\u064b \u0641\u064a \u0645\u0627\u064a\u0648 \u062d\u062a\u0649 \u0623\u063a\u0633\u0637\u0633 (\u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u062a\u0628\u062f\u0623 \u0641\u064a \u0633\u0628\u062a\u0645\u0628\u0631).\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0641\u0635\u0644 \u0627\u0644\u062b\u0627\u0646\u064a: \u0639\u0627\u062f\u0629\u064b \u0641\u064a \u0646\u0648\u0641\u0645\u0628\u0631 \u062d\u062a\u0649 \u062f\u064a\u0633\u0645\u0628\u0631 (\u0627\u0644\u062f\u0631\u0627\u0633\u0629 \u062a\u0628\u062f\u0623 \u0641\u064a \u064a\u0646\u0627\u064a\u0631).\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003e4. \u0645\u0627 \u0634\u0631\u0648\u0637 \u0627\u0644\u0642\u0628\u0648\u0644 \u0641\u064a \u0627\u0644\u0645\u0646\u062d\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u0627\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u062b\u0627\u0646\u0648\u064a\u0629 \u0627\u0644\u0639\u0627\u0645\u0629 \u0623\u0648 \u0645\u0627 \u064a\u0639\u0627\u062f\u0644\u0647\u0627.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u062a\u0641\u0631\u063a \u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u0644\u062f\u0631\u0627\u0633\u0629.\u003c/li\u003e\u003cli\u003e\u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0627\u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0648\u0627\u0644\u0644\u0648\u0627\u0626\u062d \u0627\u0644\u062c\u0627\u0645\u0639\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0627\u062c\u062a\u064a\u0627\u0632 \u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u0643\u062b\u0641 (\u0644\u063a\u064a\u0631 \u0627\u0644\u0646\u0627\u0637\u0642\u064a\u0646 \u0628\u0627\u0644\u0639\u0631\u0628\u064a\u0629).\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003e5. \u0645\u0627 \u0647\u064a \u0627\u0644\u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u0627\u0644\u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u062b\u0627\u0646\u0648\u064a\u0629 \u0648\u0643\u0634\u0648\u0641 \u0627\u0644\u062f\u0631\u062c\u0627\u062a \u0645\u0635\u062f\u0642\u0629 \u0631\u0633\u0645\u064a\u064b\u0627.\u003c/li\u003e\u003cli\u003e\u062c\u0648\u0627\u0632 \u0633\u0641\u0631 \u0633\u0627\u0631\u064a \u0627\u0644\u0645\u0641\u0639\u0648\u0644.\u003c/li\u003e\u003cli\u003e\u0635\u0648\u0631 \u0634\u062e\u0635\u064a\u0629.\u003c/li\u003e\u003cli\u003e\u0634\u0647\u0627\u062f\u0629 \u062d\u0633\u0646 \u0633\u064a\u0631\u0629 \u0648\u0633\u0644\u0648\u0643.\u003c/li\u003e\u003cli\u003e\u062a\u0642\u0631\u064a\u0631 \u0637\u0628\u064a \u064a\u062b\u0628\u062a \u0627\u0644\u0644\u064a\u0627\u0642\u0629 \u0627\u0644\u0635\u062d\u064a\u0629.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003e6. \u0643\u064a\u0641 \u064a\u062a\u0645 \u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u0637\u0644\u0628\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u064a\u0645\u0643\u0646 \u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u0637\u0644\u0628 \u0639\u0628\u0631 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0631\u0633\u0645\u064a \u0644\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629\u060c \u062d\u064a\u062b \u064a\u062a\u0645 \u062a\u0639\u0628\u0626\u0629 \u0646\u0645\u0648\u0630\u062c \u0627\u0644\u062a\u0642\u062f\u064a\u0645 \u0648\u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e7. \u0647\u0644 \u062a\u0648\u062c\u062f \u0628\u0631\u0627\u0645\u062c \u062f\u0631\u0627\u0633\u064a\u0629 \u0645\u062d\u062f\u062f\u0629 \u0645\u0634\u0645\u0648\u0644\u0629 \u0641\u064a \u0627\u0644\u0645\u0646\u062d\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u0634\u0645\u0644 \u062c\u0645\u064a\u0639 \u0627\u0644\u062a\u062e\u0635\u0635\u0627\u062a \u0627\u0644\u0645\u062a\u0627\u062d\u0629 \u0641\u064a \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u0627\u0644\u0642\u0627\u0633\u0645\u064a\u0629\u060c \u0648\u0627\u0644\u062a\u064a \u062a\u064f\u062f\u0631\u0633 \u0628\u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0623\u0648 \u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629 \u062d\u0633\u0628 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e8. \u0645\u0627 \u0647\u064a \u0627\u0644\u0625\u062c\u0631\u0627\u0621\u0627\u062a \u0628\u0639\u062f \u0627\u0644\u0642\u0628\u0648\u0644\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u0628\u0639\u062f \u0627\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0627\u0644\u0642\u0628\u0648\u0644:\u003c/p\u003e\u003cul\u003e\u003cli\u003e\u062a\u064f\u0635\u062f\u0631 \u0627\u0644\u062c\u0627\u0645\u0639\u0629 \u062a\u0623\u0634\u064a\u0631\u0629 \u0627\u0644\u0637\u0627\u0644\u0628.\u003c/li\u003e\u003cli\u003e\u064a\u062a\u0645 \u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0633\u0643\u0646 \u0648\u0627\u0644\u0625\u0642\u0627\u0645\u0629.\u003c/li\u003e\u003cli\u003e\u064a\u062d\u0635\u0644 \u0627\u0644\u0637\u0627\u0644\u0628 \u0639\u0644\u0649 \u0625\u0631\u0634\u0627\u062f\u0627\u062a \u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629 \u0644\u0628\u062f\u0621 \u0627\u0644\u062f\u0631\u0627\u0633\u0629.\u003c/li\u003e\u003c/ul\u003e\u003cp\u003e\u003cstrong\u003e9. \u0647\u0644 \u064a\u0645\u0643\u0646 \u0627\u0644\u0639\u0645\u0644 \u0623\u062b\u0646\u0627\u0621 \u0627\u0644\u062f\u0631\u0627\u0633\u0629\u061f\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u0644\u0627\u060c \u0627\u0644\u0645\u0646\u062d\u0629 \u062a\u0634\u062a\u0631\u0637 \u0627\u0644\u062a\u0641\u0631\u063a \u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u0644\u062f\u0631\u0627\u0633\u0629\u060c \u0648\u0644\u0627 \u064a\u064f\u0633\u0645\u062d \u0644\u0644\u0637\u0644\u0627\u0628 \u0628\u0627\u0644\u0639\u0645\u0644 \u062e\u0644\u0627\u0644 \u0641\u062a\u0631\u0629 \u0627\u0644\u062f\u0631\u0627\u0633\u0629.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e\u0627\u0637\u0651\u0644\u0639 \u0639\u0644\u0649 \u0627\u0644\u0645\u0632\u064a\u062f \u0645\u0646\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003e\u0645\u0646\u062d \u062f\u0631\u0627\u0633\u064a\u0629\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e\u0627\u0637\u0651\u0644\u0639 \u0639\u0644\u0649 \u0627\u0644\u0645\u0632\u064a\u062f \u0645\u0646\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003e\u0627\u0644\u0632\u0645\u0627\u0644\u0627\u062a\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003e\u0627\u0644\u0645\u062a\u0627\u062d\u0629 \u0639\u0644\u0649 \u0641\u0631\u0635\u0629\u003c/strong\u003e\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e\u0625\u0644\u064a\u0643 \u0623\u064a\u0636\u0627\u064b:\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003e\u0623\u0634\u0647\u0631 \u0628\u0631\u0627\u0645\u062c \u0627\u0644\u0645\u0646\u062d \u0627\u0644\u062f\u0631\u0627\u0633\u064a\u0629 \u0641\u064a \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629\u003c/strong\u003e\u003c/p\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e\u003c/div\u003e"}]}});